export type Cell = [number, number];

const cellKey = (x: number, y: number): string => `${x},${y}`;

const areNeighbors = (a: Cell, b: Cell): boolean =>
  (a[0] !== b[0] || a[1] !== b[1]) &&
  Math.abs(a[0] - b[0]) <= 1 &&
  Math.abs(a[1] - b[1]) <= 1;

const countNeighbors = (cell: Cell, cells: Cell[]): number =>
  cells.filter((other) => areNeighbors(cell, other)).length;

export const nextGeneration = (cells: Cell[]): Cell[] => {
  const survivors: Cell[] = cells.filter((cell) => {
    const n = countNeighbors(cell, cells);
    return n === 2 || n === 3;
  });

  const liveSet = new Set(cells.map(([x, y]) => cellKey(x, y)));
  const candidates = new Map<string, Cell>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        const key = cellKey(nx, ny);
        if (!liveSet.has(key)) {
          candidates.set(key, [nx, ny]);
        }
      }
    }
  }

  const births: Cell[] = [];
  for (const cell of candidates.values()) {
    if (countNeighbors(cell, cells) === 3) {
      births.push(cell);
    }
  }

  return [...survivors, ...births];
};

